document.addEventListener("DOMContentLoaded",function(){const e=new URLSearchParams(window.location.search).get("project");fetch("data/all-personal-work.json").then(e=>e.json()).then(t=>{const n=document.getElementById("all-projects-grid");if(!n)return;let o=null;t.forEach((t,r)=>{const c=document.createElement("div");c.classList.add("project-card"),c.id=t.id,c.innerHTML=`\n                    <div class="project-image">\n                        <img src="${t.image}" alt="${t.title}" loading="lazy">\n                        <div class="view-project">VIEW PROJECT</div>\n                    </div>\n                    <div class="project-content">\n                        <span class="project-index">\n                            ${String(r+1).padStart(2,"0")}\n                        </span>\n                        <h3>${t.title}</h3>\n                        ${t.subtitle?`<h4>${t.subtitle}</h4>`:""}\n                        <p>${t.description}</p>\n                    </div>\n                `,c.style.cursor="pointer",c.addEventListener("click",()=>{window.location.href=`projects/${t.id}.html`}),n.appendChild(c),t.id===e&&(o=c)}),o&&setTimeout(()=>{o.scrollIntoView({behavior:"smooth",block:"center"}),o.style.borderColor="var(--accent)",setTimeout(()=>{o.style.borderColor=""},2e3)},300)}).catch(e=>console.error("Personal projects loading error:",e))});